#elif defined(ENA_VEC_ISA)
#ifdef ENA_TILING
#if (NDS_VEC_RVV_VERSION >= 1000)
    /*
     * Direct convolution with fused bias + requantize.
     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
     * against the full transposed weight row (all output channels).
     * Processes 4 output pixels at a time, sharing weight loads.
     * Eliminates im2col buffer and q32 intermediate buffer.
     *
     * Register plan:
     *   v0-v3   (M4 e32): Accumulator pixel 1
     *   v4-v7   (M4 e32): Accumulator pixel 2
     *   v8-v11  (M4 e32): Accumulator pixel 3
     *   v12-v15 (M4 e32): Accumulator pixel 4
     *   v16     (M1 e8):  Weight vector load
     */
    const int in_tensor_ch = 3;
    long i_ker_y, i_ker_x, ch;

    const long align_byte = 64;
    q7_t *pOut = out_tensor;
    long vl;

    /* Allocate transposed weight buffer from in_tmp_buf */
    q7_t *src2 = (q7_t *)in_tmp_buf;
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);

    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* Total output pixels */
    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;

    /* Process 4 output pixels at a time */
    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
        long out_x4 = (pixel_idx + 3) % out_tensor_dim;

        /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;

            /* Load bias into 4 M4 accumulators at e32/M4 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE32_V(NDS_VEC_V0, bias + ch_off);
            NDS_VEC_VLE32_V(NDS_VEC_V4, bias + ch_off);
            NDS_VEC_VLE32_V(NDS_VEC_V8, bias + ch_off);
            NDS_VEC_VLE32_V(NDS_VEC_V12, bias + ch_off);

            /* Set e8/M1 once for all vqmacc accumulation (e8*e8->e32, M1 input, M4 acc) */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            /* Accumulate over all K positions */
            if (pad == 0)
            {
                /* Fast path: no padding means all pixels are interior — skip boundary checks */
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride + i_ker_y;
                    long in_row2 = out_y2 * stride + i_ker_y;
                    long in_row3 = out_y3 * stride + i_ker_y;
                    long in_row4 = out_y4 * stride + i_ker_y;

                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride + i_ker_x;
                        long in_col2 = out_x2 * stride + i_ker_x;
                        long in_col3 = out_x3 * stride + i_ker_x;
                        long in_col4 = out_x4 * stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;

                            /* Load transposed weight row into v16 at e8/M1 */
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);

                            /* Get input scalars — no boundary checks needed */
                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                            q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                            q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];

                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                /* General path: check boundaries for padding */
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride - pad + i_ker_y;
                    long in_row2 = out_y2 * stride - pad + i_ker_y;
                    long in_row3 = out_y3 * stride - pad + i_ker_y;
                    long in_row4 = out_y4 * stride - pad + i_ker_y;

                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride - pad + i_ker_x;
                        long in_col2 = out_x2 * stride - pad + i_ker_x;
                        long in_col3 = out_x3 * stride - pad + i_ker_x;
                        long in_col4 = out_x4 * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;

                            /* Load transposed weight row into v16 at e8/M1 */
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);

                            /* Get input scalars with boundary checks */
                            q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                                in_col1 >= 0 && in_col1 < in_tensor_dim)
                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                                in_col2 >= 0 && in_col2 < in_tensor_dim)
                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
                                in_col3 >= 0 && in_col3 < in_tensor_dim)
                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
                                in_col4 >= 0 && in_col4 < in_tensor_dim)
                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];

                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                        }
                    }
                }
            }

            /* Requantize pixel 1: shift, scale, narrow, clip, store */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            /* Requantize pixel 2 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, 0);
            NDS_VEC_VSB_V(NDS_VEC_V4, pOut + out_tensor_ch + ch_off);

            /* Requantize pixel 3 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut + 2 * out_tensor_ch + ch_off);

            /* Requantize pixel 4 */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSRA_VX(NDS_VEC_V12, NDS_VEC_V12, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V12, NDS_VEC_V12, out_scale);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, post_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, 0);
            NDS_VEC_VSB_V(NDS_VEC_V12, pOut + 3 * out_tensor_ch + ch_off);

            ch_off += vl;
        }
        pOut += 4 * out_tensor_ch;
    }

    /* Handle remaining 0-3 pixels one at a time */
    for (; pixel_idx < total_pixels; pixel_idx++)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        /* Channel-striping loop */
        long ch_off = 0;
        while (ch_off < out_tensor_ch)
        {
            long ch_remain = out_tensor_ch - ch_off;

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE32_V(NDS_VEC_V0, bias + ch_off);

            /* Set e8/M1 once for all vqmacc accumulation */
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

            if (pad == 0)
            {
                /* Fast path: no padding — skip boundary checks */
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }
            else
            {
                /* General path: check boundaries for padding */
                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
                {
                    long in_row1 = out_y1 * stride - pad + i_ker_y;
                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                    {
                        long in_col1 = out_x1 * stride - pad + i_ker_x;
                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                        for (ch = 0; ch < in_tensor_ch; ch++)
                        {
                            long k_pos = k_base + ch;
                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
                            q7_t a1 = 0;
                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                                in_col1 >= 0 && in_col1 < in_tensor_dim)
                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        }
                    }
                }
            }

            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSB_V(NDS_VEC_V0, pOut + ch_off);

            ch_off += vl;
        }
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */
    //cache is 512KB, type is q7
    uint32_t tiling_size = 256;
    //num of columnar
    int col_counter = 0;
    const int in_tensor_ch = 3;
    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
